#!/usr/bin/env python3\n\"\"\"\nPerformance tests for ViperMind Python Tutor\nTests response times, concurrent users, and system load\n\"\"\"\n\nimport asyncio\nimport aiohttp\nimport time\nimport statistics\nimport sys\nimport os\nfrom concurrent.futures import ThreadPoolExecutor\nfrom typing import List, Dict, Any\nfrom dotenv import load_dotenv\n\nload_dotenv()\n\nBASE_URL = \"http://localhost:8000/api/v1\"\n\nclass PerformanceTester:\n    \"\"\"Performance testing suite for ViperMind\"\"\"\n    \n    def __init__(self):\n        self.base_url = BASE_URL\n        self.auth_token = None\n        self.test_results = {}\n    \n    async def run_performance_tests(self) -> bool:\n        \"\"\"Run all performance tests\"\"\"\n        print(\"⚡ ViperMind Performance Testing Suite\")\n        print(\"=\" * 60)\n        \n        # Setup authentication\n        if not await self._setup_auth():\n            print(\"❌ Failed to setup authentication for performance tests\")\n            return False\n        \n        tests = [\n            (\"API Response Time\", self._test_api_response_times),\n            (\"Concurrent Users\", self._test_concurrent_users),\n            (\"Assessment Generation Load\", self._test_assessment_generation_load),\n            (\"Database Query Performance\", self._test_database_performance),\n            (\"Memory Usage\", self._test_memory_usage)\n        ]\n        \n        overall_success = True\n        \n        for test_name, test_func in tests:\n            print(f\"\\n🔍 Testing {test_name}...\")\n            try:\n                success = await test_func()\n                if success:\n                    print(f\"✅ {test_name} - PASSED\")\n                else:\n                    print(f\"❌ {test_name} - FAILED\")\n                    overall_success = False\n            except Exception as e:\n                print(f\"💥 {test_name} - ERROR: {str(e)}\")\n                overall_success = False\n        \n        self._print_performance_summary(overall_success)\n        return overall_success\n    \n    async def _setup_auth(self) -> bool:\n        \"\"\"Setup authentication for performance tests\"\"\"\n        async with aiohttp.ClientSession() as session:\n            # Try to login with test user\n            login_data = {\n                \"email_or_username\": \"authtest@example.com\",\n                \"password\": \"testpass123\"\n            }\n            \n            try:\n                async with session.post(f\"{self.base_url}/auth/login-json\", json=login_data) as response:\n                    if response.status == 200:\n                        auth_data = await response.json()\n                        self.auth_token = auth_data[\"access_token\"]\n                        return True\n            except Exception:\n                pass\n        \n        return False\n    \n    async def _test_api_response_times(self) -> bool:\n        \"\"\"Test API endpoint response times\"\"\"\n        endpoints = [\n            (\"/curriculum/structure\", \"GET\", None),\n            (\"/curriculum/progress\", \"GET\", None),\n            (\"/auth/me\", \"GET\", None),\n            (\"/dashboard/overview\", \"GET\", None)\n        ]\n        \n        response_times = []\n        headers = {\"Authorization\": f\"Bearer {self.auth_token}\"} if self.auth_token else {}\n        \n        async with aiohttp.ClientSession() as session:\n            for endpoint, method, data in endpoints:\n                times = []\n                \n                # Test each endpoint 10 times\n                for _ in range(10):\n                    start_time = time.time()\n                    \n                    try:\n                        if method == \"GET\":\n                            async with session.get(f\"{self.base_url}{endpoint}\", headers=headers) as response:\n                                await response.text()\n                        elif method == \"POST\":\n                            async with session.post(f\"{self.base_url}{endpoint}\", json=data, headers=headers) as response:\n                                await response.text()\n                        \n                        end_time = time.time()\n                        times.append((end_time - start_time) * 1000)  # Convert to ms\n                        \n                    except Exception as e:\n                        print(f\"   Error testing {endpoint}: {str(e)}\")\n                        continue\n                \n                if times:\n                    avg_time = statistics.mean(times)\n                    max_time = max(times)\n                    min_time = min(times)\n                    \n                    print(f\"   {endpoint}: avg={avg_time:.1f}ms, min={min_time:.1f}ms, max={max_time:.1f}ms\")\n                    response_times.extend(times)\n        \n        if response_times:\n            overall_avg = statistics.mean(response_times)\n            self.test_results[\"api_response_time\"] = {\n                \"average_ms\": overall_avg,\n                \"max_ms\": max(response_times),\n                \"min_ms\": min(response_times),\n                \"total_requests\": len(response_times)\n            }\n            \n            # Pass if average response time is under 500ms\n            success = overall_avg < 500\n            print(f\"   Overall average: {overall_avg:.1f}ms ({'✅' if success else '❌'})\")\n            return success\n        \n        return False\n    \n    async def _test_concurrent_users(self) -> bool:\n        \"\"\"Test system performance with concurrent users\"\"\"\n        concurrent_users = [5, 10, 20]\n        \n        for user_count in concurrent_users:\n            print(f\"   Testing {user_count} concurrent users...\")\n            \n            start_time = time.time()\n            \n            # Create tasks for concurrent requests\n            tasks = []\n            for i in range(user_count):\n                task = self._simulate_user_session(i)\n                tasks.append(task)\n            \n            # Run all tasks concurrently\n            results = await asyncio.gather(*tasks, return_exceptions=True)\n            \n            end_time = time.time()\n            total_time = end_time - start_time\n            \n            # Count successful sessions\n            successful = sum(1 for r in results if r is True)\n            success_rate = successful / user_count\n            \n            print(f\"     {successful}/{user_count} sessions successful ({success_rate:.1%})\")\n            print(f\"     Total time: {total_time:.1f}s\")\n            \n            self.test_results[f\"concurrent_users_{user_count}\"] = {\n                \"success_rate\": success_rate,\n                \"total_time\": total_time,\n                \"successful_sessions\": successful\n            }\n            \n            # Fail if success rate is below 90%\n            if success_rate < 0.9:\n                print(f\"     ❌ Success rate too low: {success_rate:.1%}\")\n                return False\n        \n        return True\n    \n    async def _simulate_user_session(self, user_id: int) -> bool:\n        \"\"\"Simulate a typical user session\"\"\"\n        try:\n            async with aiohttp.ClientSession() as session:\n                headers = {\"Authorization\": f\"Bearer {self.auth_token}\"} if self.auth_token else {}\n                \n                # Simulate user actions\n                actions = [\n                    (\"GET\", \"/curriculum/structure\"),\n                    (\"GET\", \"/curriculum/progress\"),\n                    (\"GET\", \"/dashboard/overview\")\n                ]\n                \n                for method, endpoint in actions:\n                    async with session.get(f\"{self.base_url}{endpoint}\", headers=headers) as response:\n                        if response.status != 200:\n                            return False\n                    \n                    # Small delay between requests\n                    await asyncio.sleep(0.1)\n                \n                return True\n                \n        except Exception:\n            return False\n    \n    async def _test_assessment_generation_load(self) -> bool:\n        \"\"\"Test assessment generation under load\"\"\"\n        print(\"   Testing assessment generation performance...\")\n        \n        if not self.auth_token:\n            print(\"     ⚠️ Skipping - no authentication\")\n            return True\n        \n        # Generate multiple assessments concurrently\n        assessment_count = 5\n        start_time = time.time()\n        \n        tasks = []\n        for i in range(assessment_count):\n            task = self._generate_test_assessment()\n            tasks.append(task)\n        \n        results = await asyncio.gather(*tasks, return_exceptions=True)\n        \n        end_time = time.time()\n        total_time = end_time - start_time\n        \n        successful = sum(1 for r in results if r is True)\n        success_rate = successful / assessment_count\n        \n        print(f\"     Generated {successful}/{assessment_count} assessments in {total_time:.1f}s\")\n        print(f\"     Average time per assessment: {total_time/assessment_count:.1f}s\")\n        \n        self.test_results[\"assessment_generation\"] = {\n            \"success_rate\": success_rate,\n            \"total_time\": total_time,\n            \"avg_time_per_assessment\": total_time / assessment_count\n        }\n        \n        # Pass if we can generate assessments in reasonable time (< 10s each)\n        return (total_time / assessment_count) < 10\n    \n    async def _generate_test_assessment(self) -> bool:\n        \"\"\"Generate a test assessment\"\"\"\n        try:\n            async with aiohttp.ClientSession() as session:\n                headers = {\"Authorization\": f\"Bearer {self.auth_token}\"}\n                \n                # First get a topic ID\n                async with session.get(f\"{self.base_url}/curriculum/structure\") as response:\n                    if response.status != 200:\n                        return False\n                    \n                    structure = await response.json()\n                    topic_id = structure[\"levels\"][0][\"sections\"][0][\"topics\"][0][\"id\"]\n                \n                # Generate assessment\n                assessment_data = {\n                    \"target_id\": topic_id,\n                    \"assessment_type\": \"quiz\",\n                    \"difficulty\": \"medium\",\n                    \"question_count\": 4\n                }\n                \n                async with session.post(f\"{self.base_url}/assessments/generate\", \n                                      json=assessment_data, headers=headers) as response:\n                    return response.status == 200\n                    \n        except Exception:\n            return False\n    \n    async def _test_database_performance(self) -> bool:\n        \"\"\"Test database query performance\"\"\"\n        print(\"   Testing database query performance...\")\n        \n        # Test multiple database-heavy endpoints\n        db_endpoints = [\n            \"/curriculum/progress\",\n            \"/assessments/history\",\n            \"/dashboard/overview\"\n        ]\n        \n        query_times = []\n        headers = {\"Authorization\": f\"Bearer {self.auth_token}\"} if self.auth_token else {}\n        \n        async with aiohttp.ClientSession() as session:\n            for endpoint in db_endpoints:\n                for _ in range(5):  # Test each endpoint 5 times\n                    start_time = time.time()\n                    \n                    try:\n                        async with session.get(f\"{self.base_url}{endpoint}\", headers=headers) as response:\n                            await response.text()\n                            \n                        end_time = time.time()\n                        query_times.append((end_time - start_time) * 1000)\n                        \n                    except Exception:\n                        continue\n        \n        if query_times:\n            avg_query_time = statistics.mean(query_times)\n            max_query_time = max(query_times)\n            \n            print(f\"     Average query time: {avg_query_time:.1f}ms\")\n            print(f\"     Max query time: {max_query_time:.1f}ms\")\n            \n            self.test_results[\"database_performance\"] = {\n                \"avg_query_time_ms\": avg_query_time,\n                \"max_query_time_ms\": max_query_time,\n                \"total_queries\": len(query_times)\n            }\n            \n            # Pass if average query time is under 200ms\n            return avg_query_time < 200\n        \n        return False\n    \n    async def _test_memory_usage(self) -> bool:\n        \"\"\"Test memory usage patterns\"\"\"\n        print(\"   Testing memory usage...\")\n        \n        try:\n            import psutil\n            \n            # Get current process memory usage\n            process = psutil.Process()\n            memory_before = process.memory_info().rss / 1024 / 1024  # MB\n            \n            # Perform memory-intensive operations\n            await self._perform_memory_intensive_operations()\n            \n            memory_after = process.memory_info().rss / 1024 / 1024  # MB\n            memory_increase = memory_after - memory_before\n            \n            print(f\"     Memory before: {memory_before:.1f}MB\")\n            print(f\"     Memory after: {memory_after:.1f}MB\")\n            print(f\"     Memory increase: {memory_increase:.1f}MB\")\n            \n            self.test_results[\"memory_usage\"] = {\n                \"memory_before_mb\": memory_before,\n                \"memory_after_mb\": memory_after,\n                \"memory_increase_mb\": memory_increase\n            }\n            \n            # Pass if memory increase is reasonable (< 100MB)\n            return memory_increase < 100\n            \n        except ImportError:\n            print(\"     ⚠️ psutil not available, skipping memory test\")\n            return True\n        except Exception as e:\n            print(f\"     ❌ Memory test error: {str(e)}\")\n            return False\n    \n    async def _perform_memory_intensive_operations(self):\n        \"\"\"Perform operations that might use memory\"\"\"\n        if not self.auth_token:\n            return\n        \n        # Simulate multiple concurrent requests\n        tasks = []\n        for _ in range(10):\n            task = self._simulate_user_session(0)\n            tasks.append(task)\n        \n        await asyncio.gather(*tasks, return_exceptions=True)\n    \n    def _print_performance_summary(self, overall_success: bool):\n        \"\"\"Print performance test summary\"\"\"\n        print(\"\\n\" + \"=\" * 60)\n        print(\"📊 PERFORMANCE TEST SUMMARY\")\n        print(\"=\" * 60)\n        \n        if self.test_results:\n            print(\"\\n📈 Performance Metrics:\")\n            \n            # API Response Time\n            if \"api_response_time\" in self.test_results:\n                api_data = self.test_results[\"api_response_time\"]\n                print(f\"   API Response Time: {api_data['average_ms']:.1f}ms avg (target: <500ms)\")\n            \n            # Concurrent Users\n            concurrent_tests = [k for k in self.test_results.keys() if k.startswith(\"concurrent_users_\")]\n            if concurrent_tests:\n                print(f\"   Concurrent Users: Tested up to {len(concurrent_tests) * 5} users\")\n                for test in concurrent_tests:\n                    data = self.test_results[test]\n                    user_count = test.split(\"_\")[-1]\n                    print(f\"     {user_count} users: {data['success_rate']:.1%} success rate\")\n            \n            # Assessment Generation\n            if \"assessment_generation\" in self.test_results:\n                assess_data = self.test_results[\"assessment_generation\"]\n                print(f\"   Assessment Generation: {assess_data['avg_time_per_assessment']:.1f}s avg (target: <10s)\")\n            \n            # Database Performance\n            if \"database_performance\" in self.test_results:\n                db_data = self.test_results[\"database_performance\"]\n                print(f\"   Database Queries: {db_data['avg_query_time_ms']:.1f}ms avg (target: <200ms)\")\n            \n            # Memory Usage\n            if \"memory_usage\" in self.test_results:\n                mem_data = self.test_results[\"memory_usage\"]\n                print(f\"   Memory Usage: +{mem_data['memory_increase_mb']:.1f}MB (target: <100MB)\")\n        \n        if overall_success:\n            print(\"\\n🎉 All Performance Tests Passed!\")\n            print(\"\\n✅ Performance Benchmarks Met:\")\n            print(\"   - API response times under 500ms\")\n            print(\"   - System handles concurrent users (90%+ success rate)\")\n            print(\"   - Assessment generation under 10s\")\n            print(\"   - Database queries under 200ms\")\n            print(\"   - Memory usage within acceptable limits\")\n            print(\"\\n🚀 System performance is production-ready!\")\n        else:\n            print(\"\\n❌ Some Performance Tests Failed!\")\n            print(\"   Review the metrics above and optimize accordingly.\")\n            print(\"   Consider scaling resources or optimizing code.\")\n\nasync def main():\n    \"\"\"Main performance test function\"\"\"\n    tester = PerformanceTester()\n    success = await tester.run_performance_tests()\n    return success\n\nif __name__ == \"__main__\":\n    try:\n        success = asyncio.run(main())\n        sys.exit(0 if success else 1)\n    except KeyboardInterrupt:\n        print(\"\\n⏹️ Performance tests interrupted by user\")\n        sys.exit(1)\n    except Exception as e:\n        print(f\"\\n💥 Performance tests failed with error: {str(e)}\")\n        sys.exit(1)\n"